import { useChat } from 'ai/react';

function truncateMessages(messages: any[], maxTokens: number = 100000) {
  let totalTokens = 0;
  const kept: any[] = [];

  // Keep system prompt + last N messages
  for (let i = messages.length - 1; i >= 0; i--) {
    const msgTokens = messages[i].content.length / 4; // Rough estimate
    if (totalTokens + msgTokens > maxTokens) break;

    kept.unshift(messages[i]);
    totalTokens += msgTokens;
  }

  return kept;
}

export function SafeChat() {
  const { messages, append } = useChat();

  const safeMessages = truncateMessages(messages);

  return (
    <Chat messages={safeMessages} />
  );
}
