import { streamText } from 'ai';

async function compressContext(messages: any[]) {
  const recent = messages.slice(-5);
  const old = messages.slice(0, -5);

  if (old.length === 0) return recent;

  const summary = await generateText({
    model: openai('gpt-4o-mini'),
    prompt: `Summarize this conversation in 200 tokens: ${JSON.stringify(old)}`,
    maxTokens: 200,
  });

  return [{ role: 'system', content: `Prior context summary: ${summary.text}` }, ...recent];
}

export async function POST(req: NextRequest) {
  const { messages } = await req.json();
  const compressed = await compressContext(messages);

  const result = await streamText({
    model: openai('gpt-4o'),
    messages: compressed,
  });

  return result.toAIStreamResponse();
}
