import { createStreamableUI } from 'ai/rsc';

function createAgentBuffer(messages: any[], maxMessages = 20) {
  // Prioritize: system > tools > assistant > user
  const prioritized = messages.sort((a, b) => {
    const priority = { system: 0, tool: 1, assistant: 2, user: 3 };
    return priority[a.role] - priority[b.role];
  });

  return prioritized.slice(-maxMessages);
}

export async function agentAction() {
